-- -----------------------------------------------------------------------------
-- LESSON: Introduction (bb-lesson-intro)
-- -----------------------------------------------------------------------------
UPDATE lessons 
SET content_json = '{"verbatim_content": "Introduction\nIn this program you will model and create a robust ball and beam controller by creating an engineering model, designing control loop architecture, and deploying code on a real control system.\nYou''ll work with a collection of 3D printed parts, electronics, and a wooden platform originally developed by Ian Carey. This project will help you develop an understanding of control theory, physics, and software written in Python and C++. It includes a combination of model-based design and hands-on testing which are techniques used in industry for designing and deploying control systems.\nThroughout the program you''ll build your project incrementally using provided training materials, reference implementations, and various examples. These resources are designed to support you without removing the need for engineering decision making.\nIf you need help, email support@shortcct.com with your specific questions and a zip file including any files relevant to your project. Remember, virtual support is available for 3 months after your product delivery date.", "source": "Ball and Beam Documentation for Kayla PDF"}'
WHERE id = 'bb-lesson-intro';


